import { cva, type VariantProps } from "class-variance-authority";
import * as React from "react";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-xl text-sm font-medium transition-colors duration-150 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50",
  {
    variants: {
      variant: {
        default:
          "bg-primary text-primary-foreground shadow-panel hover:bg-primary/90",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "text-foreground hover:bg-foreground/5",
        outline:
          "border border-border bg-card/70 text-foreground hover:bg-foreground/5",
      },
      size: {
        default: "h-11 px-4 py-2",
        sm: "h-9 rounded-lg px-3",
        lg: "h-12 rounded-2xl px-5 text-base",
        icon: "h-9 w-9 rounded-lg",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {}

export const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, ...props }, ref) => (
    <button
      ref={ref}
      className={cn(buttonVariants({ variant, size }), className)}
      {...props}
    />
  ),
);

Button.displayName = "Button";

import { cva, type VariantProps } from "class-variance-authority";
import type * as React from "react";

import { cn } from "@/lib/utils";

const badgeVariants = cva(
  "inline-flex items-center rounded-full border px-2.5 py-1 text-xs font-medium uppercase tracking-[0.18em]",
  {
    variants: {
      variant: {
        default: "border-primary/20 bg-primary/10 text-primary",
        secondary: "border-border bg-secondary text-secondary-foreground",
        outline: "border-border/80 bg-background/60 text-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
);

export interface BadgeProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof badgeVariants> {}

export function Badge({ className, variant, ...props }: BadgeProps) {
  return (
    <div className={cn(badgeVariants({ variant }), className)} {...props} />
  );
}

import type {
  FormatRule,
  FormatRuleKind,
  ImportStage,
} from "@chat-exporter/shared";

import type { ViewMode } from "@/components/format-workspace/types";

const viewLabels: Record<ViewMode, string> = {
  reader: "HTML",
  markdown: "Markdown",
  handover: "Übergabe",
  json: "JSON",
};

const roleLabels: Record<string, string> = {
  assistant: "Assistent",
  markdown: "Markdown",
  system: "System",
  tool: "Werkzeug",
  user: "Nutzer",
};

const blockTypeLabels: Record<string, string> = {
  code: "Codeblock",
  heading: "Überschrift",
  list: "Liste",
  "markdown-lines": "Markdown-Zeilen",
  paragraph: "Absatz",
  quote: "Zitat",
  table: "Tabelle",
};

const ruleKindLabels: Record<FormatRuleKind, string> = {
  clipboard: "Zwischenablage",
  export_profile: "Export-Profil",
  inline_semantics: "Inline-Semantik",
  render: "Darstellung",
  structure: "Struktur",
};

const jobStatusLabels: Record<string, string> = {
  completed: "Bereit",
  failed: "Fehlgeschlagen",
  queued: "Warteschlange",
  processing: "Import läuft",
};

export function getJobStatusLabel(status: string) {
  return jobStatusLabels[status] ?? jobStatusLabels.processing;
}

const importStageLabels: Record<
  ImportStage | "queued",
  { label: string; detail: string }
> = {
  queued: {
    label: "Wartet auf Start",
    detail:
      "Der Job ist in der Warteschlange und startet, sobald ein Worker frei ist.",
  },
  validate: {
    label: "Link wird geprüft",
    detail: "Der Link wird geprüft und dem passenden Importer zugeordnet.",
  },
  fetch: {
    label: "Seite wird geladen",
    detail: "Die freigegebene Seite wird geöffnet und als Quelle erfasst.",
  },
  extract: {
    label: "Nachrichten werden extrahiert",
    detail: "Die Unterhaltung wird aus dem Markup des Anbieters extrahiert.",
  },
  normalize: {
    label: "Transkript wird bereinigt",
    detail: "Rohfragmente werden in lesbare Nachrichten umgewandelt.",
  },
  structure: {
    label: "Struktur wird repariert",
    detail: "Abschnitte mit zusätzlichem Bereinigungsbedarf werden korrigiert.",
  },
  render: {
    label: "Ausgaben werden erzeugt",
    detail: "Reader- und Exportformate werden vorbereitet.",
  },
  done: {
    label: "Bereit",
    detail: "Das Transkript ist bereit.",
  },
};

export function getImportStageLabel(stage: ImportStage | "queued") {
  return importStageLabels[stage]?.label ?? stage;
}

export function getImportStageDescription(stage: ImportStage | "queued") {
  return importStageLabels[stage]?.detail ?? "";
}

export function getImportStageEntry(stage: ImportStage | "queued") {
  return importStageLabels[stage] ?? { label: stage, detail: "" };
}

export const adjustmentLabels = {
  send: "Senden",
  sendPending: "Wird gesendet...",
  cancel: "Abbrechen",
  discard: "Verwerfen",
  dismiss: "Verstanden",
  download: "Download",

  adjustmentPlaceholder: "Beschreibe kurz, wie diese Stelle aussehen soll.",
  followUpPlaceholder: "Noch etwas anpassen?",

  loadingMessage: "Ich bereite diese Stelle gerade für die Anpassung vor.",
  appliedHint:
    "Die Änderung ist schon sichtbar. Du kannst weiter anpassen oder eine neue Stelle markieren.",
  defaultHint:
    "Die KI antwortet kurz und setzt klare Änderungen sofort direkt in dieser Ansicht um.",
  closeLabel: "Anpassung schließen",
  createRuleLabel: "Regel erstellen",
  inputLabel: "Anpassungsanfrage",

  guideInstruction:
    "Markiere die Stelle, die anders aussehen soll. Beschreibe dann kurz deinen Wunsch, und die Änderung erscheint direkt hier.",
  guideNote: "Du musst kein Regel-JSON lesen oder eine Vorschau vergleichen.",

  endAdjustMode: "Anpassungsmodus beenden",

  edit: "Bearbeiten",
  endEdit: "Bearbeitung beenden",

  copied: "Kopiert!",

  versions: "Versionen",
  downloadAction: "Herunterladen",
  copyAllAction: "Kopieren",
  copyAllSuccess: "Kopiert!",
} as const;

export function getAdjustViewLabel(view: ViewMode) {
  return `${getViewLabel(view)} anpassen`;
}

export function getEndAdjustLabel() {
  return adjustmentLabels.endAdjustMode;
}

export function getViewLabel(view: ViewMode) {
  return viewLabels[view];
}

export function getRoleLabel(role: string) {
  return roleLabels[role] ?? role;
}

export function getBlockTypeLabel(blockType: string) {
  return blockTypeLabels[blockType] ?? blockType;
}

export function getRuleKindLabel(kind: FormatRuleKind) {
  return ruleKindLabels[kind];
}

export function formatMarkdownLinesLabel(start: number, end: number) {
  return `Markdown-Zeilen ${start}-${end}`;
}

export function formatMessageBlockLabel(
  role: string,
  index: number,
  blockType: string,
) {
  return `${getRoleLabel(role)}-Nachricht ${index} · ${getBlockTypeLabel(blockType)}`;
}

export const rulesLabels = {
  activeRulesCount: (count: number) =>
    count > 0 ? `${count} ${count === 1 ? "Regel" : "Regeln"} aktiv` : "Regeln",
  noActiveRules: "Keine aktiven Regeln.",
  allImports: "Für alle Imports",
  thisImportOnly: "Nur dieser Import",
  loading: "Wird geladen...",
  rationale: "Begründung",
  defaultRationale:
    "Diese Regel wurde aus einer früheren Anpassungssession für diesen Import erzeugt.",
  exactScopeNote: "Diese Regel gilt nur für die ursprüngliche Auswahl.",
  globalScopeNote: "Diese Regel gilt für alle Imports in diesem Format.",
  undoPending: "Wird rückgängig gemacht...",
  undo: "Rückgängig",
} as const;

export const miscLabels = {
  transcriptLoading: "Transkript wird vorbereitet",
  importFailed: "Import fehlgeschlagen",
  errorInPhase: (phase: string) => `Fehler in Phase: ${phase}`,
  viewLoadError: "Diese Ansicht konnte nicht geladen werden.",
  retryButton: "Erneut versuchen",
  adjustmentLoadError: "Anpassungen konnten nicht geladen werden.",
} as const;

export function getRuleLabel(rule: FormatRule) {
  const summary = rule.instruction.trim();

  if (summary.length <= 72) {
    return summary;
  }

  return `${summary.slice(0, 69).trimEnd()}...`;
}

{
  "$schema": "https://ui.shadcn.com/schema.json",
  "style": "default",
  "rsc": false,
  "tsx": true,
  "tailwind": {
    "css": "src/styles/globals.css",
    "baseColor": "slate",
    "cssVariables": true,
    "prefix": ""
  },
  "aliases": {
    "components": "@/components",
    "utils": "@/lib/utils"
  }
}

import { defaultRegistry } from "@chat-exporter/shared";
import {
  Check,
  Copy,
  Download,
  Eye,
  EyeOff,
  History,
  Pencil,
  Settings2,
} from "lucide-react";

import {
  adjustmentLabels,
  getAdjustViewLabel,
  getEndAdjustLabel,
} from "@/components/format-workspace/labels";
import { RulesListModal } from "@/components/format-workspace/rules-list-modal";
import type { EditMode, ViewMode } from "@/components/format-workspace/types";
import type { useFormatRules } from "@/components/format-workspace/use-format-rules";
import { Button } from "@/components/ui/button";

const outputViews = defaultRegistry.getAll().map((f) => ({
  value: f.id as ViewMode,
  label: f.label,
}));

type CompletedToolbarProps = {
  adjustModeEnabled: boolean;
  copySuccess?: boolean;
  deletionsCount?: number;
  editMode: EditMode;
  isAdjustableView: boolean;
  rules: ReturnType<typeof useFormatRules>;
  showDeleted?: boolean;
  snapshotCount?: number;
  view: ViewMode;
  onCopyAll?: () => void;
  onDownloadMarkdown?: () => void;
  onEditModeChange: (mode: EditMode) => void;
  onToggleAdjustMode: () => void;
  onToggleShowDeleted?: () => void;
  onVersionsClick?: () => void;
  onViewChange: (view: ViewMode) => void;
};

export function CompletedToolbar({
  adjustModeEnabled,
  copySuccess,
  deletionsCount,
  editMode,
  isAdjustableView,
  rules,
  showDeleted,
  snapshotCount,
  view,
  onCopyAll,
  onDownloadMarkdown,
  onEditModeChange,
  onToggleAdjustMode,
  onToggleShowDeleted,
  onVersionsClick,
  onViewChange,
}: CompletedToolbarProps) {
  return (
    <div className="space-y-2">
      <div data-testid="toolbar-format-row" className="flex flex-wrap gap-2">
        {outputViews.map((outputView) => (
          <Button
            key={outputView.value}
            data-testid={`format-view-${outputView.value}`}
            type="button"
            size="sm"
            variant={view === outputView.value ? "default" : "outline"}
            onClick={() => onViewChange(outputView.value)}
          >
            {outputView.label}
          </Button>
        ))}
      </div>

      <div
        data-testid="toolbar-action-row"
        className="flex flex-wrap items-center gap-2"
      >
        <Button
          data-testid="toolbar-download"
          type="button"
          size="icon"
          variant="outline"
          title={adjustmentLabels.downloadAction}
          disabled={!onDownloadMarkdown}
          onClick={onDownloadMarkdown}
        >
          <Download className="h-4 w-4" />
        </Button>

        <Button
          data-testid="toolbar-copy-all"
          type="button"
          size="icon"
          variant="outline"
          title={
            copySuccess
              ? adjustmentLabels.copyAllSuccess
              : adjustmentLabels.copyAllAction
          }
          disabled={!onCopyAll}
          onClick={onCopyAll}
        >
          {copySuccess ? (
            <Check className="h-4 w-4" />
          ) : (
            <Copy className="h-4 w-4" />
          )}
        </Button>

        {snapshotCount && snapshotCount > 0 ? (
          <Button
            data-testid="toolbar-versions"
            type="button"
            size="icon"
            variant="outline"
            title={adjustmentLabels.versions}
            onClick={onVersionsClick}
          >
            <History className="h-4 w-4" />
          </Button>
        ) : null}

        {deletionsCount && deletionsCount > 0 ? (
          <Button
            type="button"
            size="sm"
            variant={showDeleted ? "default" : "outline"}
            onClick={onToggleShowDeleted}
          >
            {showDeleted ? (
              <EyeOff className="mr-2 h-4 w-4" />
            ) : (
              <Eye className="mr-2 h-4 w-4" />
            )}
            {showDeleted
              ? "Gelöschte ausblenden"
              : `${deletionsCount} gelöscht`}
          </Button>
        ) : null}

        {isAdjustableView ? (
          <>
            <RulesListModal
              disablingRuleById={rules.disablingRuleById}
              expandedRuleId={rules.expandedRuleId}
              explanationErrorById={rules.explanationErrorById}
              explanationLoadingById={rules.explanationLoadingById}
              promotingRuleById={rules.promotingRuleById}
              rules={rules.activeRules}
              view={view}
              getExplanationDetail={rules.getExplanationDetail}
              onDemoteRule={(ruleId) => {
                void rules.handleDemoteRule(ruleId);
              }}
              onDisableRule={(ruleId) => {
                void rules.handleDisableRule(ruleId);
              }}
              onHoverRule={(ruleId) => rules.setHoveredRuleId(ruleId)}
              onLeaveRule={() => rules.setHoveredRuleId(null)}
              onPromoteRule={(ruleId) => {
                void rules.handlePromoteRule(ruleId);
              }}
              onToggleRuleExplanation={rules.handleToggleRuleExplanation}
            />
            <Button
              data-testid={`toggle-adjust-mode-${view}`}
              type="button"
              size="icon"
              variant={adjustModeEnabled ? "default" : "outline"}
              title={
                adjustModeEnabled
                  ? getEndAdjustLabel()
                  : getAdjustViewLabel(view)
              }
              onClick={onToggleAdjustMode}
            >
              <Settings2 className="h-4 w-4" />
            </Button>
          </>
        ) : null}

        {view === "reader" ? (
          <Button
            data-testid="toggle-edit-mode"
            type="button"
            size="icon"
            variant={editMode === "edit" ? "default" : "outline"}
            title={
              editMode === "edit"
                ? adjustmentLabels.endEdit
                : adjustmentLabels.edit
            }
            onClick={() =>
              onEditModeChange(editMode === "edit" ? "view" : "edit")
            }
          >
            <Pencil className="h-4 w-4" />
          </Button>
        ) : null}
      </div>
    </div>
  );
}

import type { AdjustmentSessionDetail } from "@chat-exporter/shared";
import {
  autoUpdate,
  flip,
  offset,
  shift,
  useFloating,
} from "@floating-ui/react";
import { X } from "lucide-react";
import {
  type FormEvent,
  memo,
  useEffect,
  useLayoutEffect,
  useRef,
  useState,
} from "react";
import { adjustmentLabels } from "@/components/format-workspace/labels";
import type {
  FloatingAdjustmentAnchor,
  ViewMode,
} from "@/components/format-workspace/types";

type AdjustmentPopoverProps = {
  anchor: FloatingAdjustmentAnchor | null;
  containerRef: React.RefObject<HTMLElement | null>;
  draftMessage: string;
  error: string | null;
  isLoading: boolean;
  isSubmitting: boolean;
  onClose: () => void;
  onDraftMessageChange: (value: string) => void;
  onRejectLastChange: (() => void) | undefined;
  onSubmitMessage: (event: FormEvent<HTMLFormElement>) => void;
  open: boolean;
  sessionDetail: AdjustmentSessionDetail | null;
  showReply: boolean;
  view: ViewMode;
};

function getLastAssistantMessage(
  sessionDetail: AdjustmentSessionDetail | null,
) {
  return (
    sessionDetail?.messages
      .slice()
      .reverse()
      .find((message) => message.role === "assistant")?.content ?? null
  );
}

/** Debounce loading indicator to avoid flashing the overlay for fast API responses. */
const LOADING_DEBOUNCE_MS = 300;

function useDebouncedLoading(isLoading: boolean) {
  const [showLoading, setShowLoading] = useState(false);

  useEffect(() => {
    if (!isLoading) {
      setShowLoading(false);
      return;
    }
    const timer = setTimeout(() => setShowLoading(true), LOADING_DEBOUNCE_MS);
    return () => clearTimeout(timer);
  }, [isLoading]);

  return showLoading;
}

// Isolated textarea — prevents re-renders from parent state changes (isLoading, sessionDetail)
// from touching the textarea DOM node, which would cause a placeholder repaint.
const DraftTextarea = memo(function DraftTextarea({
  value,
  placeholder,
  onChangeRef,
}: {
  value: string;
  placeholder: string;
  onChangeRef: React.RefObject<(value: string) => void>;
}) {
  return (
    <textarea
      data-testid="adjustment-draft-message"
      className="min-h-24 w-full rounded-2xl border border-border/80 bg-background px-3 py-3 text-sm text-foreground outline-none placeholder:text-muted-foreground focus:border-primary/50 focus:ring-2 focus:ring-primary/20"
      placeholder={placeholder}
      value={value}
      onChange={(event) => onChangeRef.current?.(event.target.value)}
    />
  );
});

const PopoverContent = memo(function PopoverContent({
  draftMessage,
  error,
  isLoading,
  isSubmitting,
  onClose,
  onDraftMessageChange,
  onRejectLastChange,
  onSubmitMessage,
  sessionDetail,
  showReply,
  view: _view,
}: Omit<AdjustmentPopoverProps, "anchor" | "containerRef" | "open">) {
  const lastAssistantMessage = getLastAssistantMessage(sessionDetail);
  const showLoadingOverlay = useDebouncedLoading(isLoading);

  const onChangeRef = useRef(onDraftMessageChange);
  onChangeRef.current = onDraftMessageChange;

  const placeholder = showReply
    ? adjustmentLabels.followUpPlaceholder
    : adjustmentLabels.adjustmentPlaceholder;

  return (
    <div className="overflow-hidden rounded-[1.4rem] border border-border bg-background shadow-[0_24px_80px_-32px_rgba(15,23,42,0.5)]">
      <div className="flex items-center justify-between gap-3 border-b border-border/80 px-4 py-3">
        <p className="text-[11px] font-semibold uppercase tracking-[0.2em] text-primary">
          {adjustmentLabels.createRuleLabel}
        </p>
        <button
          className="rounded-full p-1 text-muted-foreground transition hover:bg-foreground/5 hover:text-foreground"
          type="button"
          onClick={onClose}
        >
          <span className="sr-only">{adjustmentLabels.closeLabel}</span>
          <X className="h-4 w-4" />
        </button>
      </div>

      <div className="relative overflow-y-auto px-4 py-4">
        {error ? (
          <div
            data-testid="adjustment-error"
            className="absolute inset-x-4 top-4 z-10 rounded-2xl border border-red-300/40 bg-red-100/70 px-3 py-3 text-sm text-red-900"
          >
            {error}
          </div>
        ) : null}

        {showLoadingOverlay ? (
          <div className="absolute inset-x-4 top-4 z-10 rounded-2xl border border-border/80 bg-card/95 px-3 py-3 text-sm text-muted-foreground">
            {adjustmentLabels.loadingMessage}
          </div>
        ) : null}

        {showReply && lastAssistantMessage ? (
          <div
            data-testid="adjustment-last-reply"
            className="mb-3 rounded-2xl border border-primary/20 bg-primary/5 px-3 py-3 text-sm text-foreground"
          >
            <p className="whitespace-pre-wrap">{lastAssistantMessage}</p>
          </div>
        ) : null}

        <form className="space-y-3" onSubmit={onSubmitMessage}>
          {/* biome-ignore lint/a11y/noLabelWithoutControl: DraftTextarea contains a textarea */}
          <label className="block text-sm text-foreground">
            <span className="sr-only">{adjustmentLabels.inputLabel}</span>
            <DraftTextarea
              value={draftMessage}
              placeholder={placeholder}
              onChangeRef={onChangeRef}
            />
          </label>

          <p className="px-3 text-sm text-muted-foreground">
            {showReply
              ? adjustmentLabels.appliedHint
              : adjustmentLabels.defaultHint}
          </p>

          <div className="flex items-center justify-between gap-3">
            <button
              className="inline-flex items-center justify-center rounded-xl border border-border/80 bg-background px-4 py-2 text-sm font-medium text-foreground transition hover:bg-foreground/5"
              type="button"
              onClick={onClose}
            >
              {adjustmentLabels.cancel}
            </button>
            {showReply && !isLoading && onRejectLastChange != null ? (
              <button
                className="inline-flex items-center justify-center rounded-xl border border-border/80 bg-background px-4 py-2 text-sm font-medium text-foreground transition hover:bg-foreground/5"
                type="button"
                onClick={onRejectLastChange}
              >
                {adjustmentLabels.discard}
              </button>
            ) : null}
            <button
              data-testid="adjustment-send"
              className="inline-flex items-center justify-center rounded-xl bg-primary px-4 py-2 text-sm font-medium text-primary-foreground transition hover:opacity-95 disabled:cursor-not-allowed disabled:opacity-60"
              disabled={
                isLoading || isSubmitting || draftMessage.trim().length === 0
              }
              type="submit"
            >
              {isSubmitting
                ? adjustmentLabels.sendPending
                : adjustmentLabels.send}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
});

export function AdjustmentPopover({
  anchor,
  containerRef,
  open,
  ...contentProps
}: AdjustmentPopoverProps) {
  const { refs, floatingStyles, isPositioned } = useFloating({
    open,
    placement: "top-start",
    middleware: [offset(12), flip({ padding: 16 }), shift({ padding: 16 })],
    whileElementsMounted: autoUpdate,
  });

  useLayoutEffect(() => {
    if (!anchor) return;
    refs.setPositionReference({
      getBoundingClientRect() {
        const container = containerRef.current;
        if (!container) {
          return {
            x: 0,
            y: 0,
            top: 0,
            left: 0,
            bottom: 0,
            right: 0,
            width: 0,
            height: 0,
          };
        }
        const cr = container.getBoundingClientRect();
        const scrollTop = container.scrollTop;
        const top = anchor.top - scrollTop + cr.top;
        const left = anchor.left + cr.left;
        return {
          x: left,
          y: top,
          top,
          left,
          bottom: top + anchor.height,
          right: left + anchor.width,
          width: anchor.width,
          height: anchor.height,
        };
      },
    });
  }, [anchor, containerRef, refs]);

  const visible = open && isPositioned;

  return (
    <div
      ref={refs.setFloating}
      data-testid={`adjustment-popover-${contentProps.view}`}
      className="z-50 w-[28rem] max-w-[calc(100vw-2rem)]"
      style={{
        ...floatingStyles,
        visibility: visible ? "visible" : "hidden",
        pointerEvents: visible ? "auto" : "none",
      }}
      aria-hidden={!visible}
    >
      <PopoverContent {...contentProps} />
    </div>
  );
}

import {
  adjustmentLabels,
  getAdjustViewLabel,
} from "@/components/format-workspace/labels";
import type { ViewMode } from "@/components/format-workspace/types";

type AdjustmentModeGuideProps = {
  onDismiss: () => void;
  view: ViewMode;
};

export function AdjustmentModeGuide({
  onDismiss,
  view,
}: AdjustmentModeGuideProps) {
  return (
    <div className="pointer-events-none fixed inset-x-4 bottom-6 z-20 flex justify-center">
      <div
        data-testid={`adjustment-mode-guide-${view}`}
        className="pointer-events-auto w-full max-w-md rounded-[1.4rem] border border-border/80 bg-background/96 p-4 shadow-[0_24px_80px_-32px_rgba(15,23,42,0.45)] backdrop-blur"
      >
        <p className="text-[11px] font-semibold uppercase tracking-[0.2em] text-primary">
          {getAdjustViewLabel(view)}
        </p>
        <p className="mt-2 text-sm text-foreground">
          {adjustmentLabels.guideInstruction}
        </p>
        <div className="mt-3 flex items-center justify-between gap-3 text-sm text-muted-foreground">
